class MyCalendarThree:
    def __init__(self):
        self.delta = defaultdict(int)
    def book(self, start: int, end: int) -> int:
        self.delta[start] += 1
        self.delta[end] -= 1
        cur = ans = 0
        for t in sorted(self.delta.keys()):
            cur += self.delta[t]
            ans = max(ans, cur)
        return ans

