class MyCalendarThree {
    map<int,int> d;
public:
    int book(int start, int end) {
        d[start]++; d[end]--;
        int cur=0, ans=0;
        for (auto& [t,v]: d) { cur+=v; ans=max(ans,cur); }
        return ans;
    }
};

